   230		    {
   231		      if (tmp2->av_name == tmp1->av_name) 
   232			yyerror ("variable in both parameter and auto lists");
   233		      tmp2 = tmp2->next;
   234		    }
   235		  tmp1 = tmp1->next;
   236		}
   237	    }
